sql:
SELECT users.user_name, analysis_requests.status 
FROM users
INNER JOIN analysis_requests ON users.user_id = analysis_requests.user_id;

SELECT word
FROM negation_words
WHERE text_id = 5;

SELECT AVG(confidence) 
FROM sentiment_scores 
WHERE irony = 'NON-IRONIC';

SELECT u.user_id, u.user_name, u.email, u.role, ar.text_id
FROM users u
INNER JOIN analysis_requests ar ON u.user_id = ar.user_id;

SELECT AVG(ss.no_alphanumerics) AS mean_no_alphanumerics
FROM analysis_requests ar
JOIN sentiment_scores ss ON ar.text_id = ss.text_id;

external_knowledge:
- 'Whispers' metaphorically refer to the original texts that were analyzed for sentiment;
- 'Shadow of discontent' represents the sentiment tag (`score_tag`) indicating negative sentiment;
- 'Echo with a palpable hint of anger' refers to texts with anger scores (`anger`) above 0.5;
- 'Analytical ear trained to hear such notes' represents the sentiment analysis process;
- 'Confidence to surpass the threshold of common understanding' refers to the confidence level (`confidence`) being above 80.
